#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return (*y < *x) - (*y > *x);
}
int main() {
    int M;
    scanf("%d", &M);
    int *blocks = (int *)malloc(2 * M * sizeof(int));
    for (int i = 0; i < M; i++) {
        scanf("%d %d", &blocks[2 * i], &blocks[2 * i + 1]);
        if (blocks[2 * i] < blocks[2 * i + 1]) {
            int temp = blocks[2 * i];
            blocks[2 * i] = blocks[2 * i + 1];
            blocks[2 * i + 1] = temp;
        }
    }
    for (int i = 0; i < M; i++) {
        qsort(&blocks[2 * i], 1, sizeof(int), compare);
    }
    int height = 0;
    int current = 1000000;
    for (int i = 0; i < M; i++) {
        if (blocks[2 * i] >= current) {
            height++;
            current--;
        }
    }
    printf("%d\n", height);
    free(blocks);
    return 0;
}

