import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int M = scanner.nextInt();
        int[][] blocks = new int[M][2];
        for (int i = 0; i < M; i++) {
            blocks[i][0] = scanner.nextInt();
            blocks[i][1] = scanner.nextInt();
            if (blocks[i][0] < blocks[i][1]) {
                int temp = blocks[i][0];
                blocks[i][0] = blocks[i][1];
                blocks[i][1] = temp;
            }
        }
        Arrays.sort(blocks, (a, b) -> Integer.compare(b[0], a[0]));
        int height = 0;
        int current = 1000000;
        for (int i = 0; i < M; i++) {
            if (blocks[i][0] >= current) {
                height++;
                current--;
            }
        }
        System.out.println(height);
    }
}

